/* ── Public shape ──────────────────────────────────────────────── */

export interface Source {
  title: string;
  url: string;
  snippet: string;
  author?: string;
  publisher?: string;
  date?: string;
  why?: string;
}

export interface FetchedSource {
  title: string;
  author?: string;
  publisher?: string;
  date?: string;
  markdown: string;
  embeddable: boolean;
}

/* ── TinyFish provider (default) ──────────────────────────────── */

const TINYFISH_SEARCH_URL = "https://api.search.tinyfish.ai/v1/search";
const TINYFISH_FETCH_URL = "https://api.fetch.tinyfish.ai/v1/fetch";

async function tinyfishSearch(
  query: string,
  context: string,
): Promise<Source[]> {
  const key = process.env.TINYFISH_API_KEY;
  if (!key) return [];
  try {
    const res = await fetch(TINYFISH_SEARCH_URL, {
      method: "POST",
      headers: {
        "content-type": "application/json",
        authorization: `Bearer ${key}`,
      },
      body: JSON.stringify({ query, context, num_results: 8 }),
    });
    if (!res.ok) return [];
    const data = (await res.json()) as {
      results?: Array<{
        title?: string;
        url?: string;
        snippet?: string;
        author?: string;
        publisher?: string;
        date?: string;
      }>;
    };
    return (data.results ?? []).map((r) => ({
      title: r.title ?? "(untitled)",
      url: r.url ?? "",
      snippet: r.snippet ?? "",
      author: r.author,
      publisher: r.publisher,
      date: r.date,
    }));
  } catch {
    return [];
  }
}

async function tinyfishFetch(url: string): Promise<FetchedSource | null> {
  const key = process.env.TINYFISH_API_KEY;
  if (!key) return null;
  try {
    const res = await fetch(TINYFISH_FETCH_URL, {
      method: "POST",
      headers: {
        "content-type": "application/json",
        authorization: `Bearer ${key}`,
      },
      body: JSON.stringify({ url, format: "markdown" }),
    });
    if (!res.ok) return null;
    const data = (await res.json()) as {
      title?: string;
      author?: string;
      publisher?: string;
      date?: string;
      markdown?: string;
      embeddable?: boolean;
    };
    return {
      title: data.title ?? url,
      author: data.author,
      publisher: data.publisher,
      date: data.date,
      markdown: data.markdown ?? "",
      embeddable: data.embeddable ?? false,
    };
  } catch {
    return null;
  }
}

